package com.example.login;

import android.app.Activity;
import android.content.Context;
import android.content.Intent;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.text.TextUtils;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public final class SessionManager {
    private static final String PREFS_NAME = "demo_login_prefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_TOKEN = "auth_token";

    private SessionManager() {}

    public static void saveSession(Context context, String email, String token) {
        SharedPreferences sp = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        sp.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_TOKEN, token)
                .apply();
    }

    public static boolean hasSession(Context context) {
        SharedPreferences sp = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        String email = sp.getString(KEY_EMAIL, null);
        String token = sp.getString(KEY_TOKEN, null);
        return !TextUtils.isEmpty(email) && !TextUtils.isEmpty(token);
    }

    @Nullable
    public static String getEmail(Context context) {
        return context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).getString(KEY_EMAIL, null);
    }

    @Nullable
    public static String getToken(Context context) {
        return context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).getString(KEY_TOKEN, null);
    }

    public static void clearSession(Context context) {
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE).edit().clear().apply();
    }
}

package com.example.login;

import android.os.Handler;
import android.os.Looper;

import androidx.annotation.NonNull;

public final class DemoAuthApi {

    public interface Callback {
        void onSuccess(@NonNull String email, @NonNull String authToken);
        void onError(@NonNull String message);
    }

    private DemoAuthApi() {}

    public static void login(final String email, final String password, final Callback callback) {
        new Handler(Looper.getMainLooper()).postDelayed(() -> {
            if (email == null || email.trim().isEmpty()) {
                callback.onError("Email required");
                return;
            }
            if (password == null || password.length() < 4) {
                callback.onError("Password too short");
                return;
            }
            String token = "demo_token_" + Math.abs((email + ":" + password).hashCode());
            callback.onSuccess(email.trim(), token);
        }, 900);
    }
}

